using Microsoft.EntityFrameworkCore;using Microsoft.EntityFrameworkCore.Metadata.Builders;using NutriCasa.Domain.Entities;
namespace NutriCasa.Infrastructure.Persistence.Configurations;
public class RecipeConfiguration : IEntityTypeConfiguration<Recipe>{public void Configure(EntityTypeBuilder<Recipe> builder){builder.ToTable("recipes");builder.HasKey(e => e.Id);builder.Property(e => e.Id).HasColumnName("recipe_id").HasDefaultValueSql("uuid_generate_v4()");builder.Property(e => e.Name).HasMaxLength(200).IsRequired();builder.Property(e => e.Slug).HasMaxLength(220);builder.Property(e => e.MealType).HasConversion<string>().HasMaxLength(20);builder.Property(e => e.NutritionTrack).HasConversion<string>().HasMaxLength(20);builder.Property(e => e.Ingredients).HasColumnType("jsonb").HasDefaultValueSql("'[]'::jsonb");builder.Property(e => e.BaseProteinGr).HasColumnType("decimal(7,2)");builder.Property(e => e.BaseFatGr).HasColumnType("decimal(7,2)");builder.Property(e => e.BaseCarbsGr).HasColumnType("decimal(7,2)");builder.Property(e => e.BaseNetCarbsGr).HasColumnType("decimal(7,2)");builder.Property(e => e.Source).HasConversion<string>().HasMaxLength(20);builder.Property(e => e.AvgRating).HasColumnType("decimal(3,2)");builder.Property(e => e.EstimatedCostPerServingMxn).HasColumnType("decimal(10,2)");builder.HasOne(e => e.CreatedByUser).WithMany().HasForeignKey(e => e.CreatedByUserId);builder.HasIndex(e => e.Slug).IsUnique();builder.HasQueryFilter(e => e.DeletedAt == null);}}
